import { ObjectGenerationScreen } from "@/components/object-generation/object-generation-screen";

export default function ObjectGenerationPage() {
  return <ObjectGenerationScreen />;
}

import { handleObjectGenerationRequest } from "@/lib/object-generation/runtime";

export const maxDuration = 30;

export async function POST(request: Request) {
  return handleObjectGenerationRequest(request);
}

"use client";

import {
  ArrowClockwiseIcon,
  PaperclipIcon,
  ShieldCheckIcon,
  StopIcon,
  XIcon,
} from "@phosphor-icons/react";
import type { FileUIPart } from "ai";
import {
  Attachment,
  AttachmentInfo,
  AttachmentPreview,
  AttachmentRemove,
  Attachments,
} from "@/components/ai-elements/attachments";
import {
  Conversation,
  ConversationContent,
  ConversationEmptyState,
  ConversationScrollButton,
} from "@/components/ai-elements/conversation";
import {
  Message,
  MessageContent,
  MessageResponse,
} from "@/components/ai-elements/message";
import {
  PromptInput,
  PromptInputBody,
  PromptInputFooter,
  PromptInputSubmit,
  PromptInputTextarea,
} from "@/components/ai-elements/prompt-input";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";
import { useMemo, useRef } from "react";

import { ObjectGenerationResultCard } from "./object-generation-result-card";
import {
  type DisplayReviewThreadEntry,
} from "./object-generation-session";
import { useObjectGenerationSession } from "./use-object-generation-session";

export interface ObjectGenerationWorkspaceProps {
  acceptedMediaTypes: string[];
  chatModel: string;
  isReviewAvailable: boolean;
  nodeVersion: string;
  setupMessage: string | null;
}

function getUserAttachmentParts(attachments: DisplayReviewThreadEntry["attachments"]) {
  return attachments.map(
    (attachment): FileUIPart => ({
      filename: attachment.filename,
      mediaType: attachment.mediaType,
      type: "file",
      url: attachment.previewUrl,
    })
  );
}

export function ObjectGenerationWorkspace({
  acceptedMediaTypes,
  chatModel,
  isReviewAvailable,
  nodeVersion,
  setupMessage,
}: ObjectGenerationWorkspaceProps) {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const {
    composerError,
    entries,
    hasMessages,
    inputResetKey,
    isLoading,
    pendingAttachments,
    streamErrorMessage,
    appendFiles,
    removePendingAttachment,
    retryReview,
    stopReview,
    submitReview,
  } = useObjectGenerationSession();

  const samplePrompts = useMemo(
    () => [
      "Generate a launch-risk object for this pricing page draft and flag unsupported claims.",
      "Read this policy PDF and screenshot, then generate a publishability object with evidence.",
      "Turn the attached assets into a structured moderation object with findings and next action.",
    ],
    []
  );

  return (
    <div className="grid min-h-[70svh] gap-4 lg:h-full lg:min-h-0 lg:grid-cols-[minmax(0,1fr)_20rem]">
      <section className="flex min-h-[70svh] flex-col border border-foreground/10 bg-background lg:h-full lg:min-h-0">
        {isReviewAvailable ? null : (
          <div className="border-foreground/10 border-b px-4 py-3 text-muted-foreground text-xs/relaxed">
            {setupMessage}
          </div>
        )}

        {composerError ? (
          <div className="border-foreground/10 border-b px-4 py-3 text-destructive text-xs/relaxed">
            {composerError}
          </div>
        ) : null}

        {streamErrorMessage ? (
          <div className="border-foreground/10 border-b px-4 py-3 text-destructive text-xs/relaxed">
            {streamErrorMessage}
          </div>
        ) : null}

        <Conversation className="min-h-0">
          <ConversationContent className="mx-auto flex w-full max-w-3xl flex-1 gap-6 px-4 py-6">
            {hasMessages ? (
              entries.map((entry) => {
                const attachmentParts = getUserAttachmentParts(entry.attachments);

                return (
                  <div className="space-y-4" key={entry.id}>
                    <Message from="user">
                      <MessageContent className="space-y-4 max-w-2xl">
                        {entry.prompt ? (
                          <MessageResponse>{entry.prompt}</MessageResponse>
                        ) : (
                          <p className="text-muted-foreground text-sm">
                            Attachment-only object generation request.
                          </p>
                        )}

                        {attachmentParts.length > 0 ? (
                          <Attachments variant="list">
                            {attachmentParts.map((part, index) => (
                              <Attachment
                                data={{
                                  ...part,
                                  id: `${entry.id}-${index}-${part.filename ?? "attachment"}`,
                                }}
                                key={`${entry.id}-${index}-${part.filename ?? "attachment"}`}
                              >
                                <AttachmentPreview />
                                <AttachmentInfo showMediaType />
                              </Attachment>
                            ))}
                          </Attachments>
                        ) : null}
                      </MessageContent>
                    </Message>

                    <Message from="assistant">
                      <MessageContent className="space-y-3 max-w-3xl">
                        <ObjectGenerationResultCard
                          errorMessage={entry.errorMessage}
                          result={entry.liveResult}
                          status={entry.liveStatus}
                        />

                        {entry.liveStatus !== "streaming" ? (
                          <div className="flex justify-end">
                            <Button
                              onClick={() => retryReview(entry)}
                              size="sm"
                              type="button"
                              variant="outline"
                            >
                              <ArrowClockwiseIcon className="size-3.5" />
                              Replay generation
                            </Button>
                          </div>
                        ) : null}
                      </MessageContent>
                    </Message>
                  </div>
                );
              })
            ) : (
              <ConversationEmptyState
                description="Send text, screenshots, or PDFs. The assistant message streams a structured object directly into the thread."
                icon={<ShieldCheckIcon className="size-5" />}
                title="Object generation workspace is ready"
              />
            )}
          </ConversationContent>
          <ConversationScrollButton />
        </Conversation>

        <div className="border-foreground/10 border-t px-4 py-4">
          <div className="mx-auto w-full max-w-3xl">
            <PromptInput onSubmit={({ text }) => submitReview(text)}>
              <PromptInputBody>
                {pendingAttachments.length > 0 ? (
                  <Attachments className="mb-3" variant="list">
                    {pendingAttachments.map((attachment) => (
                      <Attachment
                        data={{
                          filename: attachment.file.name,
                          id: attachment.id,
                          mediaType:
                            attachment.file.type || "application/octet-stream",
                          type: "file",
                          url: attachment.previewUrl,
                        }}
                        key={attachment.id}
                      >
                        <AttachmentPreview />
                        <AttachmentInfo showMediaType />
                        <AttachmentRemove
                          onClick={() => removePendingAttachment(attachment.id)}
                        />
                      </Attachment>
                    ))}
                  </Attachments>
                ) : null}
                <PromptInputTextarea
                  disabled={!isReviewAvailable || isLoading}
                  placeholder="Describe the object you want, attach images or PDFs, and watch the structured object stream into the assistant message."
                />
              </PromptInputBody>
              <PromptInputFooter className="flex items-center justify-between gap-3 border-foreground/10 border-t px-3 py-3">
                <div className="flex flex-wrap items-center gap-2">
                  <input
                    accept="image/*,application/pdf"
                    className="hidden"
                    key={inputResetKey}
                    multiple
                    onChange={(event) => appendFiles(event.target.files)}
                    ref={fileInputRef}
                    type="file"
                  />
                  <Button
                    onClick={() => fileInputRef.current?.click()}
                    size="sm"
                    type="button"
                    variant="outline"
                  >
                    <PaperclipIcon className="size-3.5" />
                    Attach
                  </Button>
                  <Badge variant="outline">Structured output</Badge>
                  <Badge variant="outline">useObject</Badge>
                  <Badge variant="outline">{chatModel}</Badge>
                </div>
                <div className="flex items-center gap-2">
                  {isLoading ? (
                    <Button
                      onClick={stopReview}
                      size="sm"
                      type="button"
                      variant="outline"
                    >
                      <StopIcon className="size-3.5" />
                      Stop
                    </Button>
                  ) : null}
                  <PromptInputSubmit disabled={!isReviewAvailable || isLoading} />
                </div>
              </PromptInputFooter>
            </PromptInput>

            {!hasMessages ? (
              <div className="mt-3 flex flex-wrap gap-2">
                {samplePrompts.map((prompt) => (
                  <Button
                    className={cn("max-w-full justify-start text-left")}
                    disabled={!isReviewAvailable || isLoading}
                    key={prompt}
                    onClick={() => submitReview(prompt)}
                    size="sm"
                    type="button"
                    variant="outline"
                  >
                    {prompt}
                  </Button>
                ))}
              </div>
            ) : null}
          </div>
        </div>
      </section>

      <aside className="grid content-start gap-4 border border-foreground/10 bg-background px-4 py-4 lg:min-h-0 lg:overflow-y-auto">
        <div className="space-y-2">
          <p className="text-[11px] text-muted-foreground uppercase tracking-[0.18em]">
            Runtime
          </p>
          <div className="flex flex-wrap gap-2">
            <Badge variant="outline">
              {isReviewAvailable ? "Ready" : "Setup required"}
            </Badge>
            <Badge variant="outline">{chatModel}</Badge>
            <Badge variant="outline">Node {nodeVersion.replace(/^v/, "")}</Badge>
          </div>
        </div>

        <div className="space-y-2">
          <p className="text-[11px] text-muted-foreground uppercase tracking-[0.18em]">
            Input contract
          </p>
          <p className="text-muted-foreground text-sm/relaxed">
            One request can combine freeform text with image and PDF
            attachments. The backend streams a single structured object.
          </p>
          <div className="flex flex-wrap gap-2">
            {acceptedMediaTypes.map((mediaType) => (
              <Badge key={mediaType} variant="outline">
                {mediaType}
              </Badge>
            ))}
          </div>
        </div>

        <div className="space-y-2">
          <p className="text-[11px] text-muted-foreground uppercase tracking-[0.18em]">
            Output shape
          </p>
          <p className="text-muted-foreground text-sm/relaxed">
            The assistant card is driven by a streamed object with decision,
            risk score, findings, evidence, recommended action, and open
            questions.
          </p>
        </div>
      </aside>
    </div>
  );
}

"use client";

import type { DeepPartial } from "ai";
import { Badge } from "@/components/ui/badge";
import { Progress } from "@/components/ui/progress";
import { cn } from "@/lib/utils";

import type { ObjectGenerationResult } from "@/lib/object-generation/schema";

type ReviewCardStatus = "streaming" | "ready" | "error" | "stopped";

interface ObjectGenerationResultCardProps {
  errorMessage?: string | null;
  result: DeepPartial<ObjectGenerationResult> | undefined;
  status: ReviewCardStatus;
}

function compactList<T>(items: ReadonlyArray<T | undefined> | undefined): T[] {
  return Array.isArray(items)
    ? items.filter((item): item is T => item !== undefined)
    : [];
}

function toTitleCase(value: string) {
  return value
    .split("_")
    .map((part) => part.charAt(0).toUpperCase() + part.slice(1))
    .join(" ");
}

function getDecisionVariant(
  decision: ObjectGenerationResult["decision"] | undefined
): "default" | "secondary" | "destructive" | "outline" {
  switch (decision) {
    case "approved":
      return "default";
    case "needs_review":
      return "secondary";
    case "blocked":
      return "destructive";
    default:
      return "outline";
  }
}

function getStatusCopy(status: ReviewCardStatus) {
  switch (status) {
    case "streaming":
      return "Streaming object";
    case "ready":
      return "Object ready";
    case "stopped":
      return "Generation stopped";
    case "error":
      return "Generation failed";
  }
}

export function ObjectGenerationResultCard({
  errorMessage,
  result,
  status,
}: ObjectGenerationResultCardProps) {
  const categories = compactList(result?.categories);
  const evidence = compactList(result?.evidence);
  const findings = compactList(result?.findings);
  const openQuestions = compactList(result?.openQuestions);
  const riskScore =
    typeof result?.riskScore === "number"
      ? Math.max(0, Math.min(100, result.riskScore))
      : null;

  return (
    <div className="space-y-4 border border-foreground/10 bg-background px-4 py-4">
      <div className="flex flex-wrap items-center gap-2">
        <Badge variant="outline">{getStatusCopy(status)}</Badge>
        {result?.decision ? (
          <Badge variant={getDecisionVariant(result.decision)}>
            {toTitleCase(result.decision)}
          </Badge>
        ) : null}
        {riskScore !== null ? (
          <Badge variant="outline">Risk {riskScore}/100</Badge>
        ) : null}
      </div>

      {riskScore !== null ? (
        <div className="space-y-2">
          <div className="flex items-center gap-2 text-xs">
            <span>Risk score</span>
            <span className="ml-auto text-muted-foreground tabular-nums">
              {riskScore}
            </span>
          </div>
          <Progress value={riskScore} />
        </div>
      ) : null}

      {result?.summary ? (
        <section className="space-y-1">
          <p className="text-[11px] text-muted-foreground uppercase tracking-[0.18em]">
            Summary
          </p>
          <p className="text-sm/relaxed">{result.summary}</p>
        </section>
      ) : null}

      {categories.length > 0 ? (
        <section className="space-y-2">
          <p className="text-[11px] text-muted-foreground uppercase tracking-[0.18em]">
            Categories
          </p>
          <div className="flex flex-wrap gap-2">
            {categories.map((category, index) => (
              <Badge
                className="h-auto max-w-full whitespace-normal py-1 text-left"
                key={`${category.label ?? "category"}-${index}`}
                variant="outline"
              >
                <span className="font-medium">{category.label ?? "Category"}</span>
                {category.severity ? ` · ${toTitleCase(category.severity)}` : ""}
              </Badge>
            ))}
          </div>
        </section>
      ) : null}

      {findings.length > 0 ? (
        <section className="space-y-2">
          <p className="text-[11px] text-muted-foreground uppercase tracking-[0.18em]">
            Findings
          </p>
          <div className="space-y-2">
            {findings.map((finding, index) => (
              <div
                className="border border-foreground/10 px-3 py-3"
                key={`${finding.title ?? "finding"}-${index}`}
              >
                <div className="flex flex-wrap items-center gap-2">
                  <p className="font-medium text-sm">{finding.title ?? "Finding"}</p>
                  {finding.severity ? (
                    <Badge variant="outline">{toTitleCase(finding.severity)}</Badge>
                  ) : null}
                  {finding.policyLabel ? (
                    <Badge variant="outline">{finding.policyLabel}</Badge>
                  ) : null}
                </div>
                {finding.details ? (
                  <p className="mt-2 text-muted-foreground text-sm/relaxed">
                    {finding.details}
                  </p>
                ) : null}
              </div>
            ))}
          </div>
        </section>
      ) : null}

      {evidence.length > 0 ? (
        <section className="space-y-2">
          <p className="text-[11px] text-muted-foreground uppercase tracking-[0.18em]">
            Evidence
          </p>
          <div className="space-y-2">
            {evidence.map((item, index) => (
              <div
                className="border border-foreground/10 px-3 py-3"
                key={`${item.quote ?? "evidence"}-${index}`}
              >
                <div className="flex flex-wrap items-center gap-2">
                  <Badge variant="outline">
                    {item.sourceType ? toTitleCase(item.sourceType) : "Source"}
                  </Badge>
                  {item.filename ? (
                    <span className="text-muted-foreground text-xs">
                      {item.filename}
                    </span>
                  ) : null}
                </div>
                {item.quote ? (
                  <p className="mt-2 text-sm/relaxed">"{item.quote}"</p>
                ) : null}
                {item.rationale ? (
                  <p className="mt-2 text-muted-foreground text-xs/relaxed">
                    {item.rationale}
                  </p>
                ) : null}
              </div>
            ))}
          </div>
        </section>
      ) : null}

      {result?.recommendedAction ? (
        <section className="space-y-1">
          <p className="text-[11px] text-muted-foreground uppercase tracking-[0.18em]">
            Recommended action
          </p>
          <p className="text-sm/relaxed">{result.recommendedAction}</p>
        </section>
      ) : null}

      {openQuestions.length > 0 ? (
        <section className="space-y-2">
          <p className="text-[11px] text-muted-foreground uppercase tracking-[0.18em]">
            Open questions
          </p>
          <ul className="space-y-2 text-sm/relaxed">
            {openQuestions.map((question, index) => (
              <li
                className="border border-foreground/10 px-3 py-2"
                key={`${question}-${index}`}
              >
                {question}
              </li>
            ))}
          </ul>
        </section>
      ) : null}

      {!result?.summary &&
      categories.length === 0 &&
      findings.length === 0 &&
      evidence.length === 0 &&
      !result?.recommendedAction &&
      openQuestions.length === 0 ? (
        <p
          className={cn(
            "text-sm/relaxed",
            status === "error" ? "text-destructive" : "text-muted-foreground"
          )}
        >
          {errorMessage ??
            "Waiting for the structured object to accumulate fields."}
        </p>
      ) : null}

      {status === "error" && errorMessage ? (
        <p className="text-destructive text-xs/relaxed">{errorMessage}</p>
      ) : null}
    </div>
  );
}

import type { DeepPartial } from "ai";

import type {
  ObjectGenerationAttachment,
  ObjectGenerationResult,
} from "@/lib/object-generation/schema";
import type {
  PendingReviewAttachment,
  SubmittedReviewAttachment,
} from "./convert-files-to-object-generation-inputs";

export type ReviewEntryStatus = "streaming" | "ready" | "error" | "stopped";

export interface ReviewThreadEntry {
  attachments: SubmittedReviewAttachment[];
  errorMessage: string | null;
  id: string;
  prompt: string;
  requestAttachments: ObjectGenerationAttachment[];
  result: DeepPartial<ObjectGenerationResult> | undefined;
  status: ReviewEntryStatus;
}

export interface DisplayReviewThreadEntry extends ReviewThreadEntry {
  isActive: boolean;
  liveResult: DeepPartial<ObjectGenerationResult> | undefined;
  liveStatus: ReviewEntryStatus;
}

interface CreateReviewThreadEntryInput {
  id: string;
  pendingAttachments: PendingReviewAttachment[];
  prompt: string;
  requestAttachments: ObjectGenerationAttachment[];
}

interface FinalizeReviewThreadEntryInput {
  entryId: string;
  errorMessage?: string | null;
  result: DeepPartial<ObjectGenerationResult> | undefined;
  status: ReviewEntryStatus;
}

export function createReviewThreadEntry({
  id,
  pendingAttachments,
  prompt,
  requestAttachments,
}: CreateReviewThreadEntryInput): ReviewThreadEntry {
  return {
    attachments: toSubmittedReviewAttachments(pendingAttachments),
    errorMessage: null,
    id,
    prompt,
    requestAttachments,
    result: undefined,
    status: "streaming",
  };
}

export function mergePendingReviewAttachments(
  current: PendingReviewAttachment[],
  nextAttachments: PendingReviewAttachment[]
) {
  const byId = new Map(current.map((attachment) => [attachment.id, attachment]));

  for (const attachment of nextAttachments) {
    byId.set(attachment.id, attachment);
  }

  return Array.from(byId.values());
}

export function removePendingReviewAttachment(
  current: PendingReviewAttachment[],
  attachmentId: string
) {
  const removedAttachment =
    current.find((attachment) => attachment.id === attachmentId) ?? null;

  return {
    nextAttachments: current.filter((attachment) => attachment.id !== attachmentId),
    removedAttachment,
  };
}

export function collectReviewPreviewUrls(
  pendingAttachments: PendingReviewAttachment[],
  entries: ReviewThreadEntry[]
) {
  const previewUrls = new Set<string>();

  for (const attachment of pendingAttachments) {
    previewUrls.add(attachment.previewUrl);
  }

  for (const entry of entries) {
    for (const attachment of entry.attachments) {
      previewUrls.add(attachment.previewUrl);
    }
  }

  return previewUrls;
}

export function finalizeReviewThreadEntry(
  entries: ReviewThreadEntry[],
  {
    entryId,
    errorMessage = null,
    result,
    status,
  }: FinalizeReviewThreadEntryInput
) {
  return entries.map((entry) =>
    entry.id === entryId
      ? {
          ...entry,
          errorMessage,
          result,
          status,
        }
      : entry
  );
}

export function failReviewThreadEntry(
  entries: ReviewThreadEntry[],
  entryId: string,
  errorMessage: string,
  result: DeepPartial<ObjectGenerationResult> | undefined
) {
  return finalizeReviewThreadEntry(entries, {
    entryId,
    errorMessage,
    result,
    status: "error",
  });
}

export function stopReviewThreadEntry(
  entries: ReviewThreadEntry[],
  entryId: string,
  result: DeepPartial<ObjectGenerationResult> | undefined
) {
  return finalizeReviewThreadEntry(entries, {
    entryId,
    result,
    status: "stopped",
  });
}

export function restartReviewThreadEntry(
  entries: ReviewThreadEntry[],
  entryId: string
) : ReviewThreadEntry[] {
  return entries.map((entry): ReviewThreadEntry =>
    entry.id === entryId
        ? {
            ...entry,
            errorMessage: null,
            status: "streaming" as const,
          }
      : entry
  );
}

export function toDisplayReviewThreadEntries(
  entries: ReviewThreadEntry[],
  activeEntryId: string | null,
  isLoading: boolean,
  liveObject: DeepPartial<ObjectGenerationResult> | undefined
): DisplayReviewThreadEntry[] {
  return entries.map((entry) => {
    const isActive = activeEntryId === entry.id;

    return {
      ...entry,
      isActive,
      liveResult: isActive ? liveObject ?? entry.result : entry.result,
      liveStatus: isActive && isLoading ? "streaming" : entry.status,
    };
  });
}

export function toSubmittedReviewAttachments(
  attachments: PendingReviewAttachment[]
): SubmittedReviewAttachment[] {
  return attachments.map((attachment) => ({
    filename: attachment.file.name,
    id: attachment.id,
    mediaType: attachment.file.type || "application/octet-stream",
    previewUrl: attachment.previewUrl,
  }));
}

"use client";

import { experimental_useObject as useObject } from "@ai-sdk/react";
import type { DeepPartial } from "ai";
import { useEffect, useMemo, useRef, useState } from "react";

import type {
  ObjectGenerationAttachment,
  ObjectGenerationResult,
} from "@/lib/object-generation/schema";
import { objectGenerationResultSchema } from "@/lib/object-generation/schema";
import {
  buildPendingReviewAttachment,
  convertFilesToReviewAttachments,
  type PendingReviewAttachment,
} from "./convert-files-to-object-generation-inputs";
import {
  collectReviewPreviewUrls,
  createReviewThreadEntry,
  failReviewThreadEntry,
  mergePendingReviewAttachments,
  restartReviewThreadEntry,
  stopReviewThreadEntry,
  toDisplayReviewThreadEntries,
  type DisplayReviewThreadEntry,
  type ReviewThreadEntry,
} from "./object-generation-session";

export interface ObjectGenerationSessionController {
  composerError: string | null;
  entries: DisplayReviewThreadEntry[];
  hasMessages: boolean;
  inputResetKey: number;
  isLoading: boolean;
  pendingAttachments: PendingReviewAttachment[];
  streamErrorMessage: string | null;
  appendFiles: (fileList: FileList | null) => void;
  removePendingAttachment: (attachmentId: string) => void;
  retryReview: (entry: ReviewThreadEntry) => void;
  stopReview: () => void;
  submitReview: (text: string) => Promise<void>;
}

export function useObjectGenerationSession(): ObjectGenerationSessionController {
  const [pendingAttachments, setPendingAttachments] = useState<
    PendingReviewAttachment[]
  >([]);
  const [composerError, setComposerError] = useState<string | null>(null);
  const [entries, setEntries] = useState<ReviewThreadEntry[]>([]);
  const [activeEntryId, setActiveEntryId] = useState<string | null>(null);
  const [inputResetKey, setInputResetKey] = useState(0);
  const pendingAttachmentsRef = useRef<PendingReviewAttachment[]>([]);
  const entriesRef = useRef<ReviewThreadEntry[]>([]);
  const latestObjectRef = useRef<DeepPartial<ObjectGenerationResult> | undefined>(
    undefined
  );
  const activeEntryIdRef = useRef<string | null>(null);

  const { clear, error, isLoading, object, stop, submit } = useObject<
    typeof objectGenerationResultSchema,
    ObjectGenerationResult,
    {
      attachments: ObjectGenerationAttachment[];
      prompt: string;
    }
  >({
    api: "/api/demos/object-generation",
    onError(streamError) {
      const entryId = activeEntryIdRef.current;

      if (!entryId) {
        return;
      }

      setEntries((current) =>
        failReviewThreadEntry(
          current,
          entryId,
          streamError.message,
          latestObjectRef.current
        )
      );
      setActiveEntryId(null);
    },
    async onFinish({ error: finishError, object: finalObject }) {
      const entryId = activeEntryIdRef.current;

      if (!entryId) {
        return;
      }

      const currentEntry = entriesRef.current.find((entry) => entry.id === entryId);
      const result = finalObject ?? latestObjectRef.current ?? currentEntry?.result;

      setEntries((current) =>
        current.map((entry) =>
          entry.id === entryId
            ? {
                ...entry,
                errorMessage: finishError?.message ?? null,
                result,
                status: finishError ? "error" : "ready",
              }
            : entry
        )
      );
      setActiveEntryId(null);
    },
    schema: objectGenerationResultSchema,
  });

  useEffect(() => {
    pendingAttachmentsRef.current = pendingAttachments;
  }, [pendingAttachments]);

  useEffect(() => {
    entriesRef.current = entries;
  }, [entries]);

  useEffect(() => {
    activeEntryIdRef.current = activeEntryId;
  }, [activeEntryId]);

  useEffect(() => {
    latestObjectRef.current = object;
  }, [object]);

  useEffect(() => {
    return () => {
      for (const url of collectReviewPreviewUrls(
        pendingAttachmentsRef.current,
        entriesRef.current
      )) {
        URL.revokeObjectURL(url);
      }
    };
  }, []);

  function removePendingAttachment(attachmentId: string) {
    setPendingAttachments((current) => {
      const target =
        current.find((attachment) => attachment.id === attachmentId) ?? null;

      if (target) {
        URL.revokeObjectURL(target.previewUrl);
      }

      return current.filter((attachment) => attachment.id !== attachmentId);
    });
  }

  function appendFiles(fileList: FileList | null) {
    if (!fileList) {
      return;
    }

    const nextAttachments = Array.from(fileList).map(buildPendingReviewAttachment);
    setPendingAttachments((current) =>
      mergePendingReviewAttachments(current, nextAttachments)
    );
  }

  async function submitReview(text: string) {
    const prompt = text.trim();

    if (!prompt && pendingAttachments.length === 0) {
      return;
    }

    try {
      setComposerError(null);
      const requestAttachments = await convertFilesToReviewAttachments(
        pendingAttachments.map((attachment) => attachment.file)
      );
      const entryId = crypto.randomUUID();

      setEntries((current) => [
        ...current,
        createReviewThreadEntry({
          id: entryId,
          pendingAttachments,
          prompt,
          requestAttachments,
        }),
      ]);
      setActiveEntryId(entryId);
      latestObjectRef.current = undefined;
      submit({
        attachments: requestAttachments,
        prompt,
      });
      setPendingAttachments([]);
      setInputResetKey((current) => current + 1);
    } catch (attachmentError) {
      setComposerError(
        attachmentError instanceof Error
          ? attachmentError.message
          : "Failed to prepare review attachments."
      );
    }
  }

  function stopReview() {
    const entryId = activeEntryIdRef.current;

    stop();

    if (!entryId) {
      return;
    }

    setEntries((current) =>
      stopReviewThreadEntry(current, entryId, latestObjectRef.current)
    );
    setActiveEntryId(null);
  }

  function retryReview(entry: ReviewThreadEntry) {
    if (isLoading) {
      return;
    }

    clear();
    setEntries((current) => restartReviewThreadEntry(current, entry.id));
    setActiveEntryId(entry.id);
    latestObjectRef.current = undefined;
    submit({
      attachments: entry.requestAttachments,
      prompt: entry.prompt,
    });
  }

  return {
    composerError,
    entries: useMemo(
      () => toDisplayReviewThreadEntries(entries, activeEntryId, isLoading, object),
      [entries, activeEntryId, isLoading, object]
    ),
    hasMessages: entries.length > 0,
    inputResetKey,
    isLoading,
    pendingAttachments,
    streamErrorMessage: error?.message ?? null,
    appendFiles,
    removePendingAttachment,
    retryReview,
    stopReview,
    submitReview,
  };
}

import type { ObjectGenerationAttachment } from "@/lib/object-generation/schema";

export interface PendingReviewAttachment {
  file: File;
  id: string;
  previewUrl: string;
}

export interface SubmittedReviewAttachment {
  filename: string;
  id: string;
  mediaType: string;
  previewUrl: string;
}

export function buildPendingReviewAttachment(
  file: File
): PendingReviewAttachment {
  return {
    file,
    id: `${file.name}-${file.size}-${file.lastModified}`,
    previewUrl: URL.createObjectURL(file),
  };
}

export async function convertFilesToReviewAttachments(
  files: File[]
): Promise<ObjectGenerationAttachment[]> {
  return Promise.all(
    files.map(
      (file) =>
        new Promise<ObjectGenerationAttachment>((resolve, reject) => {
          const reader = new FileReader();

          reader.onload = () => {
            if (typeof reader.result !== "string") {
              reject(new Error(`Failed to read ${file.name} as a data URL.`));
              return;
            }

            resolve({
              filename: file.name,
              mediaType: file.type || "application/octet-stream",
              url: reader.result,
            });
          };

          reader.onerror = () => {
            reject(new Error(`Failed to read ${file.name} as a data URL.`));
          };

          reader.readAsDataURL(file);
        })
    )
  );
}

